animations.cssText:
@keyframes arrow-animation { 
  0% { transform: translateZ(0px); }
  33% { transform: translate3d(0px, 1em, 0px); }
  100% { transform: translate3d(0px, 1em, 0px); }
}

@keyframes text-animation { 
  0% { transform: translateZ(0px); }
  33% { transform: translate3d(0px, 1.5em, 0px); }
  100% { transform: translate3d(0px, 1.5em, 0px); }
}
